Here's a clean implementation using `INotifyPropertyChanged`:

```csharp
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Windows.Input;

public class ProductDetailViewModel : INotifyPropertyChanged
{
    private string _name = string.Empty;
    private decimal _price;
    private bool _isAvailable;
    private bool _isBusy;

    public string Name
    {
        get => _name;
        set => SetProperty(ref _name, value);
    }

    public decimal Price
    {
        get => _price;
        set => SetProperty(ref _price, value);
    }

    public bool IsAvailable
    {
        get => _isAvailable;
        set => SetProperty(ref _isAvailable, value);
    }

    public bool IsBusy
    {
        get => _isBusy;
        set => SetProperty(ref _isBusy, value);
    }

    public ICommand LoadCommand { get; }

    public ProductDetailViewModel()
    {
        LoadCommand = new Command(async () => await LoadProductAsync());
    }

    private async Task LoadProductAsync()
    {
        if (IsBusy) return;

        try
        {
            IsBusy = true;
            // Replace with your actual data service call
            await Task.Delay(500);
            Name = "Sample Product";
            Price = 29.99m;
            IsAvailable = true;
        }
        finally
        {
            IsBusy = false;
        }
    }

    public event PropertyChangedEventHandler? PropertyChanged;

    private bool SetProperty<T>(ref T field, T value, [CallerMemberName] string? propertyName = null)
    {
        if (EqualityComparer<T>.Default.Equals(field, value)) return false;
        field = value;
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        return true;
    }
}
```

**Key points:**

- **`SetProperty<T>`** Рђћ avoids redundant notifications and eliminates boilerplate via `[CallerMemberName]`.
- **`IsBusy`** Рђћ guards against duplicate loads; bind it to an `ActivityIndicator`.
- **`Command(async Рђд)`** Рђћ MAUI's built-in `Command` handles async delegates. For production, consider `AsyncRelayCommand` from the **CommunityToolkit.Mvvm** package, which also offers `[ObservableProperty]` / `[RelayCommand]` source generators to eliminate all the boilerplate above.
